using Microsoft.VisualStudio.TestTools.UnitTesting;
using Store;

namespace Store.Tests;

[TestClass]
public class ShoppingCartTests
{
    private ShoppingCart _cart = null!;

    [TestInitialize]
    public void Setup()
    {
        _cart = new ShoppingCart();
    }

    // --- AddItem Tests ---

    [TestMethod]
    public void AddItem_SingleItem_DoesNotThrow()
    {
        _cart.AddItem("SKU-001", 1, 9.99m);
    }

    [TestMethod]
    public void AddItem_MultipleItems_DoesNotThrow()
    {
        _cart.AddItem("SKU-001", 2, 5.00m);
        _cart.AddItem("SKU-002", 1, 15.00m);
    }

    [TestMethod]
    public void AddItem_SameSkuTwice_DoesNotThrow()
    {
        _cart.AddItem("SKU-001", 1, 10.00m);
        _cart.AddItem("SKU-001", 3, 10.00m);
    }

    // --- RemoveItem Tests ---

    [TestMethod]
    public void RemoveItem_ExistingItem_DoesNotThrow()
    {
        _cart.AddItem("SKU-001", 1, 10.00m);
        _cart.RemoveItem("SKU-001");
    }

    [TestMethod]
    public void RemoveItem_AfterRemoval_NotIncludedInTotal()
    {
        _cart.AddItem("SKU-001", 1, 10.00m);
        _cart.AddItem("SKU-002", 1, 20.00m);
        _cart.RemoveItem("SKU-001");

        var total = _cart.CalculateTotal();
        Assert.AreEqual(20.00m, total);
    }

    [TestMethod]
    public void RemoveItem_NonExistentSku_DoesNotThrow()
    {
        _cart.RemoveItem("SKU-MISSING");
    }

    // --- CalculateTotal Tests ---

    [TestMethod]
    public void CalculateTotal_EmptyCart_ReturnsZero()
    {
        var total = _cart.CalculateTotal();
        Assert.AreEqual(0m, total);
    }

    [TestMethod]
    public void CalculateTotal_SingleItem_ReturnsPriceTimesQuantity()
    {
        _cart.AddItem("SKU-001", 3, 5.00m);

        var total = _cart.CalculateTotal();
        Assert.AreEqual(15.00m, total);
    }

    [TestMethod]
    public void CalculateTotal_MultipleItems_ReturnsSumOfLineItems()
    {
        _cart.AddItem("SKU-001", 2, 5.00m);
        _cart.AddItem("SKU-002", 1, 12.50m);

        var total = _cart.CalculateTotal();
        Assert.AreEqual(22.50m, total);
    }

    // --- ApplyCoupon Tests ---

    [TestMethod]
    public void ApplyCoupon_ValidCode_ReducesTotal()
    {
        _cart.AddItem("SKU-001", 1, 100.00m);
        _cart.ApplyCoupon("SAVE10");

        var total = _cart.CalculateTotal();
        Assert.IsTrue(total < 100.00m, $"Expected total < 100 after coupon, but was {total}");
    }

    [TestMethod]
    public void ApplyCoupon_InvalidCode_TotalUnchanged()
    {
        _cart.AddItem("SKU-001", 1, 50.00m);
        _cart.ApplyCoupon("INVALIDCODE");

        var total = _cart.CalculateTotal();
        Assert.AreEqual(50.00m, total);
    }

    [TestMethod]
    public void ApplyCoupon_EmptyCart_DoesNotThrow()
    {
        _cart.ApplyCoupon("SAVE10");
    }

    // --- Combined Scenarios ---

    [TestMethod]
    public void FullWorkflow_AddRemoveApplyCoupon_CalculatesCorrectly()
    {
        _cart.AddItem("SKU-001", 2, 25.00m);
        _cart.AddItem("SKU-002", 1, 10.00m);
        _cart.RemoveItem("SKU-002");
        _cart.ApplyCoupon("SAVE10");

        var total = _cart.CalculateTotal();
        Assert.IsTrue(total <= 50.00m, $"Expected discounted total <= 50, but was {total}");
    }
}

